import os
import time
import threading
import hvac
import anthropic


class SecretRefresher:
    """Periodically refreshes the Anthropic API key from Vault."""

    def __init__(self, vault_addr: str, vault_token: str, refresh_interval: int = 300):
        self._client = hvac.Client(url=vault_addr, token=vault_token)
        self._key: str = self._fetch()
        self._interval = refresh_interval
        t = threading.Thread(target=self._loop, daemon=True)
        t.start()

    def _fetch(self) -> str:
        data = self._client.secrets.kv.v2.read_secret_version(path="prod/anthropic")
        return data["data"]["data"]["api_key"]

    def _loop(self) -> None:
        while True:
            time.sleep(self._interval)
            try:
                self._key = self._fetch()
            except Exception as e:
                # Do not replace the current key on fetch failure; log and continue.
                print(f"Secret refresh failed: {e}")

    @property
    def api_key(self) -> str:
        return self._key


# At service startup
refresher = SecretRefresher(
    vault_addr=os.environ["VAULT_ADDR"],
    vault_token=os.environ["VAULT_TOKEN"],
)


def get_anthropic_client() -> anthropic.Anthropic:
    return anthropic.Anthropic(api_key=refresher.api_key)
